const { fork } = require('child_process');
const path = require('path');

let serverProcess;
function startServer() {
    const serverPath = app.isPackaged
        ? path.join(process.resourcesPath, 'python/dist/server/server.exe')
        : path.join(__dirname, '../python/dist/server/server.exe');
    serverProcess = require('child_process').spawn(serverPath);
    serverProcess.stdout.on('data', (d) => console.log(d.toString()));
}

app.on('before-quit', () => { if(serverProcess) serverProcess.kill(); });

// preload.js
const { contextBridge, ipcRenderer } = require('electron');
contextBridge.exposeInMainWorld('api', {
    search: (query) => ipcRenderer.invoke('search', query),
    download: (url, opts) => ipcRenderer.invoke('download', url, opts),
    onProgress: (cb) => ipcRenderer.on('download-progress', (_, data) => cb(data)),
    removeProgressListener: () => ipcRenderer.removeAllListeners('download-progress')
});

const { ipcMain } = require('electron');

ipcMain.handle('search', async (event, query) => {
    try {
        const resp = await fetch(`http://localhost:${PORT}/api/search`, {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({query})
        });
        return await resp.json();
    } catch (err) {
        return { error: err.message };
    }
});

const { autoUpdater } = require('electron-updater');

autoUpdater.autoDownload = true;
autoUpdater.on('update-available', (info) => {
    mainWindow.webContents.send('update-available', info.version);
});
autoUpdater.on('update-downloaded', () => {
    mainWindow.webContents.send('update-ready');
});
// Check on startup
app.whenReady().then(() => autoUpdater.checkForUpdates());

const gotLock = app.requestSingleInstanceLock();
if (!gotLock) {
    app.quit();
} else {
    app.on('second-instance', () => {
        if (mainWindow) {
            if (mainWindow.isMinimized()) mainWindow.restore();
            mainWindow.focus();
        }
    });
}

